{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyO/ip2VkCGcRvC9LW63oW77"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"14oaGJ05xjzz"},"outputs":[],"source":["import streamlit as st\n","import json\n","from google import genai\n","from google.genai import types\n","\n","# 頁面設定\n","st.set_page_config(page_title=\"附中 AI 導覽員\")\n","st.title(\"陽明交大附中 - xx導覽\")\n","\n","# 讀取背景知識\n","try:\n","\twith open('tour.json', 'r', encoding='utf-8') as f:\n","    \tcontext_data = json.load(f)\n","    \tcontext_text = json.dumps(context_data, ensure_ascii=False)\n","except FileNotFoundError:\n","\tst.error(\"找不到 tour.json 檔案\")\n","\tst.stop()\n","except Exception as e:\n","\tst.error(f\"讀取 JSON 發生錯誤：{e}\")\n","\tst.stop()\n","\n","# 初始化 API 與對話\n","if \"gemini_client\" not in st.session_state:\n","\ttry:\n","    \tapi_key = st.secrets[\"GEMINI_API_KEY\"]\n","\texcept KeyError:\n","    \tst.error(\"未找到 GEMINI_API_KEY\")\n","    \tst.stop()\n","\n","\tclient = genai.Client(api_key=api_key)\n","\tst.session_state.gemini_client = client\n","\n","\tsystem_instruction = (\n","    \tf\"你是陽明交大附中導覽員「xx」。\\n\"\n","    \tf\"請優先參考以下內容回答，若找不到請自動搜尋。\\n\\n\"\n","    \tf\"內容：\\n{context_text}\"\n","\t)\n","\n","config = types.GenerateContentConfig(\n","    \tsystem_instruction=system_instruction,\n","    \ttools=[types.Tool(google_search=types.GoogleSearch())],\n","    \ttemperature=0.7,\n","\t)\n","\tst.session_state.config = config\n","\n","\t# 設定使用 Gemini 2.5\n","\tst.session_state.chat_session = client.chats.create(\n","    \tmodel=\"gemini-2.5-flash\",\n","    \tconfig=config\n","\t)\n","\n","\tst.session_state.messages = [\n","    \t{\"role\": \"assistant\", \"content\": \"你好，我是導覽員xx，請隨時發問。\"}\n","\t]\n","# 顯示歷史紀錄\n","for msg in st.session_state.messages:\n","\twith st.chat_message(msg[\"role\"]):\n","    \tst.write(msg[\"content\"])\n","\n","# 處理輸入\n","if prompt := st.chat_input(\"想問什麼事\"):\n","\tst.chat_message(\"user\").write(prompt)\n","\tst.session_state.messages.append({\"role\": \"user\", \"content\": prompt})\n","\n","with st.spinner(\"處理中\"):\n","    \ttry:\n","        \tresponse = st.session_state.chat_session.send_message(prompt)\n","        \tresponse_text = response.text\n","\n","        \tst.chat_message(\"assistant\").write(response_text)\n","        \tst.session_state.messages.append({\"role\": \"assistant\", \"content\": response_text})\n","\n","    \texcept Exception as e:\n","        \tst.error(f\"對話發生異常：{e}\")\n","        \tst.info(\"可能是 API 或模型限制\")\n","\n"]}]}